var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임</color> 승전, 1개월 뒤\\n<color=#ffd34c>그라운드 원</color> 시립 도서관","JPN":"<color=#ffd34c>クリフォトゲーム</color>戦勝から1か月後\\n<color=#ffd34c>グラウンド・ワン</color>市立図書館","ENG":"<color=#ffd34c>Qliphoth Game</color> victory, 1 months later\\n<color=#ffd34c>Ground One</color> Municipal Library","TWN":"距<color=#ffd34c>逆卡巴拉遊戲</color>勝利，1個月後\\n<color=#ffd34c>G1</color> 市立圖書館"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 이번에 들어온 편입생이구나? 만나서 반가워.","JPN":"あなたが今度入ってきた編入生？　初めまして。","ENG":"So you're the new transfer student? Nice to meet you.","TWN":"你是這次新來的插班生吧？很高興見到你。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"편입한 지 꽤 지났는데, 서류만 접수되고 그 뒤에 아무 연락이 없어서 이렇게 찾아왔어.","JPN":"編入してから随分経つのに、書類が受理されて以降なんの連絡もないから会いに来ちゃった。","ENG":"It's been a while since you transferred on paper, but there was no contact from you after that, so I came to see you.","TWN":"你插班已經有一段時間了，但送來檔案之後就沒有任何聯繫，所以我們就來找你了。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 네…….","JPN":"あっ、はい……","ENG":"Oh, okay...","TWN":"是，是嗎……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으음, 아! 혹시 책 좋아하니?","JPN":"うーん、あ！　もしかして本が好きなの？","ENG":"Mm... Oh! Do you like books?","TWN":"嗯嗯。對了！你是不是喜歡看書？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우리 아카데미 학생들은 적어도 하나씩 부 활동을 하도록 권장하고 있거든.","JPN":"このアカデミーの生徒は、みんな何かしらの部活に入ることになってるんだよ。","ENG":"The Academy encourages its students to have at least one club activity.","TWN":"我們學院鼓勵學生至少參加一個社團。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 리온도 분명 마음에 드는 동아리를 찾을 수 있을 거야! 고전 문학 연구회는 어때?","JPN":"だからリオンちゃんも、お気に入りの部活を探してみてね！　古典文学研究会はどう？","ENG":"So I'm sure you'll find a club you like, Liona! How does Classical Literature Research Club sound?","TWN":"所以萊恩你肯定也能找到心儀的社團！古典文學研究會怎麼樣？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Uh...","TWN":"那個……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"미카 선배라고 하셨죠?","JPN":"ミカ先輩……ですよね？","ENG":"Mika, was it?","TWN":"你是米卡前輩吧？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 아카데미 총학생회의 미카★스타! 장차 세기의 대마술사가 될 몸이라구!","JPN":"うん！　アカデミー総生徒会のミカ★スター！　世紀の大魔術師になる器だよ！","ENG":"Yup! I'm Mika★Star from the Academy Student Council! I'm also going to be the greatest magician of the century!","TWN":"沒錯！學院學生會的米卡★斯塔！將來要成為世紀大魔術師的人喔！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앞으로 아카데미 생활에 궁금한 점이 있다면 얼마든지 상담해도 좋아.","JPN":"これからアカデミーでの生活について質問があったら、いつでも相談してね。","ENG":"If you have any questions about the Academy, feel free to ask me.","TWN":"如果你對未來的學院生活有任何疑問，隨時都可以諮詢我。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"죄송하지만, 동아리 활동은 힘들 것 같아요.","JPN":"すみません、部活はできそうにないです。","ENG":"I'm sorry, but I think club activities are going to be difficult for me.","TWN":"對不起，我恐怕很難參加社團活動。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저랑 같이 있으면 다들 위험해지거든요. 다른 애들한테 폐를 끼칠 수는 없어서요…….","JPN":"私と一緒にいると、みんなが危険です。他の人たちに迷惑をかけるわけには……","ENG":"People will be in danger if I'm around them. And I don't want to cause harm to others...","TWN":"如果跟我在一起，大家都會變得很危險。我不能給別人添麻煩……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아아, 프로필에서 봤어. <color=#ffd34c>토토</color>라고 했나? 그 마검 때문이구나?","JPN":"ああ、プロフィールで見たよ。<color=#ffd34c>トト</color>だっけ？　あの魔剣のせいだよね？","ENG":"Oh, I saw it in your profile. <color=#ffd34c>Toto</color>, was it? It's because of that evil sword, right?","TWN":"啊啊，我在履歷上看到過。叫<color=#ffd34c>托托</color>是吧？是因為那把魔劍吧？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"걱정하지 마. 아카데미에는 네가 생각하는 것보다 훨씬 별난 녀석들이 많거든!","JPN":"大丈夫。アカデミーにはあなたが思うよりずっと変なやつらがいっぱいいるから！","ENG":"Don't worry. There are plenty of students far weirder than you can imagine at the Academy!","TWN":"不用擔心，學院裡有很多比你想得還要奇怪的傢伙！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다들 분명 리온의 개성을 이해해 줄 거야.","JPN":"きっとみんなリオンの個性を理解してくれる。","ENG":"I'm sure everyone will understand your uniqueness.","TWN":"大家肯定會理解你的個性的！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아니요, 제 말은 그런 뜻이 아니라…….","JPN":"いいえ、私の話はそういう意味じゃなくて……","ENG":"No, that's not what I meant...","TWN":"不，我說的不是那個意思……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 아무튼 저 급한 일이 있어서……! 먼저 가봐도 될까요?","JPN":"と、とにかく急用があるので……！　先に帰ってもいいですか？","ENG":"A-anyway, I have to be somewhere...! May I be excused?","TWN":"總，總之，我有急事……！我可以先走了嗎？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아카데미에는, 당분간 못 나가게 될 것 같다고 이사장님께 말씀드릴게요.","JPN":"アカデミーには、しばらく出ないと理事長に話しておきます。","ENG":"I'll tell the chairwoman that I won't be able to attend the Academy for the time being.","TWN":"我會跟理事長說一下，我可能暫時來不了學院了。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그, 그럼……!","JPN":"じゃ、じゃあ……！","ENG":"B-bye...!","TWN":"那，那我走了……！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"얘! 잠깐만 기다려봐, 리온!","JPN":"ねえ！　ちょっと待ってよ、リオンちゃん！","ENG":"Hey! Wait up, Liona!","TWN":"喂！等一下，萊恩！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어이가 없네. 거기 서. 겁쟁이 안경!","JPN":"ふざけてるの？　待ちなさいよ。弱虫メガネ！","ENG":"You got to be kidding me. Stop right there, Shy Specs!","TWN":"真是無言。給我站住，膽小四眼蛙！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"거, 겁쟁이 안경……!?","JPN":"よ、弱虫メガネ……！？","ENG":"S-shy Specs...?!","TWN":"膽，膽小四眼蛙……？！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래, 너 말이야, 너! 편입 첫날부터 계속 결석하길래 기껏 걱정해서 찾아왔더니…….","JPN":"そう、あんただよ、あんた！　編入初日からずっと欠席で、せっかく心配して来てやったら……","ENG":"Yeah! I'm talking to you! We came all the way here because you've been absent since the first day of your transfer...","TWN":"沒錯，就是你！從插班第一天開始就一直缺席，因為擔心才過來找你的……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"보자 보자 하니까, 하늘 같은 선배님이 만만해 보여?","JPN":"先輩をバカにしてるの？","ENG":"You think your upperclassmen are a joke or something?","TWN":"我一忍再忍，你是不是覺得前輩都好欺負？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"……그런 게 아니라.","JPN":"……そうじゃなくて。","ENG":"…I didn't mean it.","TWN":"……不是那樣的。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 나이엘 그만해!","JPN":"ちょっと、ナイエル。やめてよ！","ENG":"Hey, Naielle. Quit it!","TWN":"喂，奈爾，夠了！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭘 그만해! 이게 다 총학생회가 후배들 기강을 똑바로 안 잡아서 그래!","JPN":"やめないわよ！　総生徒会が後輩の風紀を正さないからこうなるんじゃない！","ENG":"Quit what?! This is all happening because the Student Council doesn't discipline the underclassmen!","TWN":"哼！夠什麼夠！這都是因為學生會沒有好好整頓後輩們的綱紀！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이번 기회에 본때를 보여줘야 한다고!","JPN":"この際、先輩の本気を見せてやらないと！","ENG":"Now's the time to teach them a lesson!","TWN":"趁這次機會要給她點顏色看看！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어, 어쭈구리!? 지금 해보겠다 이거지!?","JPN":"ちょ、ちょっと！？　今やる気！？","ENG":"W-what the?! You trying to fight me, is that it?!","TWN":"唉唷唷——？！你現在是要和我槓上了嗎？！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 아니에요! 이건 토토가 멋대로……!","JPN":"ち、違います！　これはトトが勝手に……！","ENG":"N-no! Toto just moved on its own...!","TWN":"不，不是的！是托托自己……！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"헹! 덤빌 테면 덤벼 보시지?","JPN":"ふんっ！　かかってきなさいよ。","ENG":"Hmph! Come at me if you can!","TWN":"呵！盡管來吧！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 나이엘 님은 아카데미 최강의 쓰레기…….","JPN":"このナイエル様はアカデミー最強のゴミ……","ENG":"I, Naielle, am the Academy's best garbage–","TWN":"我奈爾可是學院的最強垃圾……."},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흐익! 에, 에이스라고!","JPN":"じゃなくて！　え、エースなんだから！","ENG":"Eek! I-I mean ace!","TWN":"咳！是，是王牌！最強王牌！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토 얌전히 좀 있어!","JPN":"トト、お願い！　大人しくして！","ENG":"Toto, stay still!","TWN":"托托，你乖乖的！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 도서관에서 무슨 소란이야?","JPN":"何だ？　図書館で何か騒ぎか？","ENG":"Huh? What's all the ruckus at the library?","TWN":"什麼呀，在圖書館裡吵什麼呀？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"쯧쯧, 요즘 것들은 정숙할 줄도 모르고…….","JPN":"チッチッ、最近の若者は騒がしいったらありゃしない……","ENG":"Tsk, tsk. Kids these days have no manners...","TWN":"嘖嘖，現在的人一點水準都沒有……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_22"},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"왜, 왜 그래!? 먼저, 덤벼보라니깐!?","JPN":"な、なによ！？　早くかかってきなさいよ！！","ENG":"W-what?! I said, come at me!","TWN":"幹，幹嘛？！我讓你先放馬過來啊？！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 역시 겁먹은 거지? 2종 슬레이어 나이엘 블루스틸 님의 기세에……!","JPN":"はは、やっぱりビビッてるんだ？　第2種スレイヤーのナイエル・ブルースチール様の勢いに……！","ENG":"Haha, scared? I knew it. You're intimidated by the Category 2 Slayer Naielle Bluestee–","TWN":"哼，哼哼，果然是被嚇到了吧？被我這個2級屠戮者奈爾‧布魯斯提爾的氣勢所……！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우, 우와아아아아아악!! 자, 자, 잘못했습니다아아아아!!","JPN":"う、うわああああああっ！！　す、す、すみませーーーーん！！","ENG":"W-WHOOOOOOA!! I-I'm sorryyyyy!!","TWN":"嗚，嗚哇啊啊啊啊啊！！好了好了！我，我錯了啊啊啊啊——！！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그만, 토토!","JPN":"ほら、トト！","ENG":"Enough, Toto!","TWN":"住手，托托！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"다, 다들 소란을 피워서 죄송합니다!","JPN":"お、お騒がせしてすみません！","ENG":"I apologize for causing such a ruckus!","TWN":"對，對不起大家，造成大家的困擾！"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"좋아. 여기라면 아무도 다칠 일 없겠지.","JPN":"ふぅ。ここなら誰も傷つけないよね。","ENG":"Okay. No one will get hurt here.","TWN":"好吧。在這裡應該不會有人受傷吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"숨어 있는 거 다 알아요, 이제 그만 나오세요.","JPN":"隠れてるの、知ってますよ。そろそろ出て来てください。","ENG":"I know you're there. Why don't you come out?","TWN":"我知道你躲起來了，快出來吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"여기는 철학부. 타겟을 확보하겠다.","JPN":"こちらは哲学部。ターゲットを確保する。","ENG":"This is Philosophy Department. Securing the target.","TWN":"這裡是哲學院，將回收目標。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L47_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"당신들은 누구죠? 이제 위저드는 존재하지 않을 텐데…….","JPN":"あなたたち、誰ですか？　もうウィザードは存在しないはずですけど……","ENG":"Who are you? I thought Wizard doesn't exist anymore...","TWN":"你們是誰？明明巫師組織已經不存在了………"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"위저드? 넌 아무것도 모르는 모양이군.","JPN":"ウィザード？　お前は何もわかってないようだな。","ENG":"Wizard? You seem to know nothing.","TWN":"巫師組織？看來你什麼都不知道。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그 <color=#ffd34c>파편</color>은 원래 우리 측 물건이었다.","JPN":"あの<color=#ffd34c>破片</color>は元々こちらの物だった。","ENG":"That <color=#ffd34c>Fragment</color> belonged to us originally.","TWN":"那個<color=#ffd34c>碎片</color>原本是我們的東西。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"순순히 넘기면 목숨만큼은 살려주지.","JPN":"素直に渡せば、命だけは助けてやる。","ENG":"Hand it over, and we will spare you your life.","TWN":"你只要乖乖地交出來，我就饒你一命。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"파편? 파편이라면…… 역시 토토를 말하는 거죠?","JPN":"破片？　破片って……やっぱりトトのことですよね？","ENG":"Fragment? When you say \\"Fragment...\\" you mean Toto, right?","TWN":"碎片？碎片的話……指的是托托吧？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"미안하지만, 토토는 아무한테도 안 넘겨!","JPN":"悪いけど、トトは誰にも渡さない！","ENG":"I'm sorry, but I'm not handing Toto over to anyone!","TWN":"對不起，我不會把托托交給任何人！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토는, 내 소중한 친구니까!","JPN":"トトは、私の大切な友だちだから！","ENG":"Because Toto is... my friend!","TWN":"因為托托是我珍貴的朋友！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"짐승 이하라고는 해도, 인간과 교감하는 파편이라니…… 희귀 케이스로군.","JPN":"獣以下とは言え、人間と意志疎通する破片とは……稀なケースだ。","ENG":"Even if it's less than a beast, a Fragment that communes with humans... A rare case, indeed.","TWN":"雖說是野獸，但卻能和人類交流的碎片……真是罕見。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"계획을 변경한다. 파편과 숙주 양쪽을 확보하여 연구재료로 사용한다.","JPN":"計画を変更しよう。破片と宿主、両方確保し研究材料として使用する。","ENG":"Change of plans. Secure both the Fragment and host to be used as our research material.","TWN":"更改計畫。回收碎片和宿主，用作研究材料。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"팔, 다리 정도는 어찌돼도 상관없어. 수단과 방법을 가리지 말고 제압하도록!","JPN":"腕と足くらいなら、どうなっても構わない。手段を選ばずに制圧しろ！","ENG":"Arms and legs are of no concern. Use all means necessary to subdue her!","TWN":"不管是手臂或大腿都好，一定要不擇手段地帶回去！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"너도 싸우고 싶은 거지, 토토?","JPN":"あなたも戦いたいんでしょ？　トト。","ENG":"You also want to fight, don't you, Toto?","TWN":"托托，你也想打一架吧？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"입마개, 풀어줄게.","JPN":"口輪、外してあげる。","ENG":"Here. Let me take off your muzzle.","TWN":"我給你解開口罩。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이젠 도망치지 않아. 토토가 날 지켜주는 것처럼 나도 토토를 지키겠어.","JPN":"もう逃げない。トトが私を守ってくれるように、私もトトを守るよ。","ENG":"I'm not running away this time. Just like how Toto protects me, I'm going to protect Toto.","TWN":"我不會再逃跑了。就像托托守護著我一樣，我也要守護托托。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토와 함께라면 난 겁쟁이가 아니니까!","JPN":"トトと一緒なら、私は弱虫じゃないから！","ENG":"Because if I'm with Toto, I'm not a scaredy-cat!","TWN":"只要和托托在一起，我就不是膽小鬼！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"지금이야! 토토!","JPN":"今だよ！　トト！","ENG":"Now! Toto!","TWN":"就是現在！托托！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"으아아악!","JPN":"うわああっ！","ENG":"AAARGH!","TWN":"呃啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"떨어져, 떨어지라고 이 괴물아!!","JPN":"放せ！　放せ、この化け物！！","ENG":"Get off me! Get off me, you monster!!","TWN":"走開，走開，你這個怪物！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토가 더 세게 물면, 당신들 동료…… 진짜 큰일 날지도 몰라!","JPN":"トトが本気で噛みついたら、あなたたちの仲間なんて……ひとたまりもないんだからね！","ENG":"If Toto bites down harder, your colleague... will be in big trouble!","TWN":"如果托托下嘴再重些，你們的同伴……說不定會出大事的！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러니까 더는 날 쫓지 않겠다고……!","JPN":"だからもう私を追わないって……！","ENG":"So tell them to stop following me, or–","TWN":"所以說不要再追我了……！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"크윽! 어, 어째서?","JPN":"くうっ！　ど、どうして？","ENG":"Kgh! W-why?","TWN":"咳！為，為什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"지금 동료가 죽어도 상관없다는 거야?","JPN":"仲間が死んでも構わないってこと？","ENG":"Don't you care if your colleague dies?","TWN":"就算讓你的同伴死了也沒關係嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"죽이지 않고, 협박을 할 정도로 정밀한 통제가 가능하다니.","JPN":"殺さずに、脅しに使えるくらい繊細なコントールができるなんて。","ENG":"Being able to threaten and precisely control it without killing...","TWN":"居然可以精准地控制，控制下手力度並進行威脅。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"아무래도 우리가 진짜를 찾은 모양이야.","JPN":"どうやら私たちは本物を見つけたようだ。","ENG":"It seems we found the one.","TWN":"看來我們找到真的了。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"어이, 거기 너! <color=#ffd34c>잔해</color>가 되어서 타겟을 제압해라!","JPN":"おい、そこのお前！　<color=#ffd34c>残骸</color>になってターゲットを制圧しろ！","ENG":"Hey, you! Become a <color=#ffd34c>Remains</color> and restrain the target!","TWN":"喂，那邊的！變成<color=#ffd34c>殘骸</color>牽制目標！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그, 그렇지만…… 그렇게 되면 저는……!!","JPN":"で、ですが……そうすれば、私は……！！","ENG":"B-but then... I'll...!","TWN":"可，可是……那樣的話，我……！！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"시끄러워! 모든 건 지식의 호수가 하나되기 위함이다! 서둘러!","JPN":"うるさい！　すべては知識の湖が一つになるためだ！　急げ！","ENG":"Shut up! Everything is for the Lake of Knowledge to become one! Do it, now!","TWN":"囉嗦！這一切都是為了讓知識湖水合而為一！快點！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"끄윽, 끄아아아아아아아아아악……!!","JPN":"くうっ、ぐああああああああぁぁぁ……！！","ENG":"Errgh... KRRAAAAAWR...!!","TWN":"呃，呃啊啊啊啊……！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"뭔가를 몸에 주입했어?","JPN":"何かを体に注入した？","ENG":"What did he just inject himself with?","TWN":"你，你往身體裡注射了什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>불완전한</color> 지식, <b>불완</b>전한 존<color=#ff3636>재들이 성</color>찬을 통해 완<b>전해</b>지리니......","JPN":"<color=#ff3636>不完全な</color>知識、<b>不完</b>全な存<color=#ff3636>在たちが聖</color>餐により完<b>全体と</b>なる……","ENG":"T<color=#ff3636>he feast</color> will <b>com</b>plete the imperfect <color=#ff3636>knowledge</color> and perfect the <b>imp</b>erfect beings.","TWN":"<color=#ff3636>不完整的</color>知識，<b>不完整</b>的存在將透過<color=#ff3636>盛宴</color>變得完整<b></b>……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이, 이게 무슨!? 갑자기 침식체로 변해버렸잖아?","JPN":"ど、どういうこと！？　いきなり侵食体に……？","ENG":"W-what?! He suddenly turned into a C.O.!","TWN":"這，這是什麼？！突然就變成了侵蝕體？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"으앗……!? 토토 거기 서……!!","JPN":"あっ……！？　トト、待って……！！","ENG":"Huh...?! Toto, stop...!!","TWN":"啊啊……？！不要過去，托托……！！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"역시 허수 에너지로 구성된 존재를 탐식하려는 성질을 가지고 있군.","JPN":"やはり虚数エネルギーで構成された存在を貪食しようとする性質を持っているな。","ENG":"It seems that it has properties of wanting to devour beings composed of Imaginary Energy.","TWN":"果然具有貪食由虛數能量組成的存在的性質。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"틀림없어. <color=#ffd34c>기생체</color>는 고고학부장이 말한 가능성을 가진 파편이다!","JPN":"間違いない。<color=#ffd34c>寄生体</color>は考古学部長が話していた可能性を持っている破片だ！","ENG":"That <color=#ffd34c>parasite</color> is without a doubt the fragment of possibilities the Dean of Archeology talked about!","TWN":"肯定沒錯。這個<color=#ffd34c>寄生物</color>是考古學教授所說的具有可能性的碎片！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"뭣들 하고 있나! 지금이다! 파편을 놓친 숙주를 제압해!","JPN":"何してる！　今だ！　破片を落とした宿主を制圧しろ！","ENG":"What are you waiting for?! Now! Subdue the host that let go of the Fragment!","TWN":"你們在做什麼！就是現在！宿主和碎片分開了！抓住她！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"으아아아……! 이, 이젠 어쩌지……?","JPN":"うわああ……！　ど、どうしよう……？","ENG":"Waah...! W-what do I do now...?","TWN":"呃啊啊啊……！現，現在怎麼辦……？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토가 없으면, 나는 그냥 겁쟁이일 뿐인데…… ","JPN":"トトがいないと、私はただの弱虫なのに…… ","ENG":"Without Toto... I'm just a scaredy-cat...","TWN":"沒有托托的我只是個膽小鬼……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"음?","JPN":"え？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이, 이건 <color=#ffd34c>봉인 사슬</color>?","JPN":"こ、これは<color=#ffd34c>封印の鎖</color>？","ENG":"I-is this a <color=#ffd34c>Sealing Chain</color>?","TWN":"這，這是<color=#ffd34c>封印鎖鏈</color>？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 설마……?","JPN":"ということは、まさか……？","ENG":"Then that means...","TWN":"難道……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"그래, 그래. 대충 니들이 생각하는 그 설마가 맞아.","JPN":"ああ、そうだ。お前らが考えているそのまさかだ。","ENG":"Yeah, yeah. It's exactly what you blokes think it is.","TWN":"沒錯，像這種劇情展開一般都會有個難道的吧。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하나, 둘, 셋, 넷…….","JPN":"いち、に、さん、し……","ENG":"One, two, three, four...","TWN":"一，二，三，四……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참, 니들은 부끄럽지도 않냐? 길바닥 싸움도 나름 매너라는 게 있다고.","JPN":"ったく、恥ずかしくねえのか？　底辺のケンカにもそれなりのマナーってもんがあるんだ。","ENG":"Blimey, aren't you ashamed of yourselves? Even street fights have their own set of rules, you know.","TWN":"你們幾個真是，也不覺得丟人嗎？在路上打架也是要講點禮貌的？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"쳇, 이렇게 된 이상 파편만이라도 회수한다! 서둘러!","JPN":"チッ、こうなった以上破片だけでも回収する！　急げ！","ENG":"Tch! We have no other choice! Prioritize the Fragment! Hurry!","TWN":"哼，就算這樣，碎片還是要收回的！動作快點！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하! 누가 그걸 가만히 지켜보고 있을 것 같아?","JPN":"は！　俺らがそれを黙って見ているとでも？","ENG":"Hah! You think we'll just sit back and watch you take it?","TWN":"哈！你以為我會看著你們收回去嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 받아! 리온!","JPN":"ほら！　リオン！","ENG":"Here, take this! Liona!","TWN":"來，接好了！萊恩！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"앗, 쇠사슬로 토토를 붙잡았어? 토토가 저렇게 얌전할 리 없는데?","JPN":"あっ、鎖でトトを捕まえた？　トトがあんなに大人しいはずないのに。","ENG":"Huh? He grabbed Toto with the chain? But there's no way Toto would be so calm.","TWN":"用鐵鍊抓住了托托？可是托托為什麼會那麼乖……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_09"},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"잠깐, 그보다 어떻게 내 이름을……?","JPN":"ちょっと、それよりどうして私の名前を……？","ENG":"Wait a minute. H-how do you know my name...?","TWN":"等等，他怎麼會知道我的名字……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"정신 바짝 차려. 이 망할 자식들은 파편만 보면 눈알 뒤집혀서 덤벼드니까.","JPN":"しっかりしろ。このクソ野郎どもは破片を見ると理性を失って襲いかかってくるからな。","ENG":"Look alive. These damned bastards go insane whenever they see a Fragment.","TWN":"打起精神來。這幫混蛋眼裡就只有碎片。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"험한 꼴 당하고 싶지 않으면 다시는 그 검 놓지 말라고.","JPN":"痛い目見たくなけりゃ、二度とその剣を落とすなよ。","ENG":"So if you don't want to be hurt, never let go of that sword again.","TWN":"要是不想重蹈覆轍，就別再鬆開那把劍了。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Okay!","TWN":"好，好的！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};